# Lightweight task-time analysis using calendar and ticket data
# Run against exported Jira/Asana/ServiceNow data

import json
from collections import defaultdict

def analyse_task_volume(ticket_data, stream_tag):
    """
    ticket_data: list of dicts with keys: id, created, resolved, type, stream_tag
    Returns volume and cycle-time stats for a given value stream tag.
    """
    stream_tickets = [t for t in ticket_data if t.get("stream_tag") == stream_tag]

    by_type = defaultdict(list)
    for ticket in stream_tickets:
        if ticket.get("resolved"):
            elapsed_days = (ticket["resolved"] - ticket["created"]).days
            by_type[ticket["type"]].append(elapsed_days)

    results = {}
    for task_type, durations in by_type.items():
        results[task_type] = {
            "count_annual": len(durations),
            "avg_cycle_time_days": sum(durations) / len(durations),
            "p90_cycle_time_days": sorted(durations)[int(len(durations) * 0.9)],
        }
    return results

